    type DbView = RemoteTables;
    type Reducers = RemoteReducers;
    type Procedures = RemoteProcedures;
    type DbUpdate = DbUpdate;
    type AppliedDiff<'r> = AppliedDiff<'r>;
    type SubscriptionHandle = SubscriptionHandle;
    type QueryBuilder = __sdk::QueryBuilder;

    fn register_tables(client_cache: &mut __sdk::ClientCache<Self>) {
        account_table::register_table(client_cache);
        account_key_table::register_table(client_cache);
        domain_table::register_table(client_cache);
        domain_member_table::register_table(client_cache);
        message_table::register_table(client_cache);
        my_account_table::register_table(client_cache);
        my_dm_domains_table::register_table(client_cache);
        my_subscribed_messages_table::register_table(client_cache);
        my_subscriptions_table::register_table(client_cache);
        subscription_table::register_table(client_cache);
    }
    const ALL_TABLE_NAMES: &'static [&'static str] = &[
        "account",
        "account_key",
        "domain",
        "domain_member",
        "message",
        "my_account",
        "my_dm_domains",
        "my_subscribed_messages",
        "my_subscriptions",
        "subscription",
    ];
